        // Last task depends on two tasks
        assert_eq!(result.tasks[3].depends_on.len(), 2);
        assert!(result.tasks[3].depends_on.contains(&"t2".to_string()));
        assert!(result.tasks[3].depends_on.contains(&"t3".to_string()));
    }

